import{c as e}from"./app.8935f5f1.js";const n={},a=e('<div class="language-text ext-text"><pre class="language-text"><code>File类常见方法：\n1，创建。\n    boolean createNewFile():在指定位置创建文件，如果该文件已经存在，则不创建，返回false。\n                        和输出流不一样，输出流对象一建立创建文件。而且文件已经存在，会覆盖。\n    boolean mkdir():创建文件夹。\n    boolean mkdirs():创建多级文件夹。\n2，删除。\n    boolean delete()：删除失败返回false。如果文件正在被使用，则删除不了返回falsel。\n    void deleteOnExit();在程序退出时删除指定文件。\n3，判断。\n    boolean exists() :文件是否存在.\n    isFile():\n    isDirectory();\n    isHidden();\n    isAbsolute();\n4，获取信息。\n    getName():\n    getPath():\n    getParent():\n    getAbsolutePath()\n    long lastModified()\n    long length()\n\n</code></pre></div><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h2><div class="language-java ext-java"><pre class="language-java"><code>\n<span class="token comment">//  递归创建</span>\n</code></pre></div>',3);n.render=function(e,n){return a};export{n as default};
